import{_ as a,o,c as i,a0 as t}from"./chunks/framework.BFy5Ffxw.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),d={name:"changelog.md"};function l(r,e,n,s,c,h){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to cymbal are documented here.</p><h2 id="_0-7-1-2026-03-26" tabindex="-1">[0.7.1] - 2026-03-26 <a class="header-anchor" href="#_0-7-1-2026-03-26" aria-label="Permalink to &quot;[0.7.1] - 2026-03-26&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Windows (amd64) binary in release pipeline — builds with Cgo on <code>windows-latest</code>, packaged as <code>.zip</code>.</li></ul><h2 id="_0-7-0-2026-03-25" tabindex="-1">[0.7.0] - 2026-03-25 <a class="header-anchor" href="#_0-7-0-2026-03-25" aria-label="Permalink to &quot;[0.7.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Flexible symbol resolution pipeline (<code>flexResolve</code>) — shared by <code>show</code>, <code>investigate</code>, and <code>context</code>: <ul><li><strong>Ambiguity auto-resolve</strong>: picks best match by path proximity and kind priority, notes alternatives in frontmatter (<code>matches: 2 (also: path:line)</code>)</li><li><strong>Dot-qualified names</strong>: <code>config.Load</code> resolves by filtering parent/path. Works for <code>pkg.Function</code> and <code>Class.method</code> patterns.</li><li><strong>Fuzzy fallback</strong>: exact → case-insensitive (<code>COLLATE NOCASE</code>) → FTS prefix match. Marks results with <code>fuzzy: true</code>.</li></ul></li><li><code>SearchSymbolsCI</code> store method for case-insensitive exact name match.</li><li><code>InvestigateResolved</code> for investigating pre-resolved symbols.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>show</code> and <code>investigate</code> no longer error on ambiguous symbols — they auto-resolve and return the best match with disambiguation hints in frontmatter.</li></ul><h2 id="_0-6-0-2026-03-25" tabindex="-1">[0.6.0] - 2026-03-25 <a class="header-anchor" href="#_0-6-0-2026-03-25" aria-label="Permalink to &quot;[0.6.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>cymbal trace &lt;symbol&gt;</code> — downward call graph traversal. Follows what a symbol calls, what those call, etc. (BFS, depth 3 default, max 5). Filters stdlib noise to surface project-defined symbols. Complementary to <code>impact</code> (upward) and <code>investigate</code> (adaptive).</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Agent integration guide (README, CLAUDE.md, AGENTS.md) restructured around three core commands: <code>investigate</code> (understand), <code>trace</code> (downward), <code>impact</code> (upward). Based on real-world observation of an agent making 22 sequential calls that trace + investigate handled in 4.</li></ul><h2 id="_0-5-1-2026-03-25" tabindex="-1">[0.5.1] - 2026-03-25 <a class="header-anchor" href="#_0-5-1-2026-03-25" aria-label="Permalink to &quot;[0.5.1] - 2026-03-25&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>show</code> and <code>investigate</code> now accept <code>file:Symbol</code> syntax to disambiguate when multiple symbols share a name (e.g., <code>cymbal show config.go:Config</code>, <code>cymbal investigate internal/config/config.go:Config</code>).</li><li><code>show</code> line range parser accepts <code>L</code>-prefixed ranges (<code>file.go:L119-L132</code>) — was advertised in README but broken.</li></ul><h2 id="_0-5-0-2026-03-25" tabindex="-1">[0.5.0] - 2026-03-25 <a class="header-anchor" href="#_0-5-0-2026-03-25" aria-label="Permalink to &quot;[0.5.0] - 2026-03-25&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>cymbal investigate &lt;symbol&gt;</code> — kind-adaptive symbol exploration. Returns the right shape of information based on what a symbol is: functions get source + callers + shallow impact; types get source + members + references; ambiguous names get ranked candidates. Eliminates the agent&#39;s decision loop of choosing between search/show/refs/impact.</li><li><code>ChildSymbols</code> store method for querying methods/fields by parent type name.</li><li>Benchmark suite now tracks output size (bytes + approximate tokens) and includes ripgrep refs/show equivalents for fair token efficiency comparison.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>TypeScript/JavaScript <code>export</code> statement dedup — exported functions, classes, interfaces, types, and enums no longer appear twice in the index (same pattern as the Python decorator fix in v0.4.1).</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>README rewritten with workflow-centric agent integration guide. <code>investigate</code> is the recommended default, specific commands are escape hatches.</li></ul><h2 id="_0-4-1-2026-03-24" tabindex="-1">[0.4.1] - 2026-03-24 <a class="header-anchor" href="#_0-4-1-2026-03-24" aria-label="Permalink to &quot;[0.4.1] - 2026-03-24&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Benchmark suite now tracks output size (bytes + approximate tokens) per query, comparing token efficiency across tools. Ripgrep refs and show equivalents added for fair comparison.</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Python decorated functions and classes no longer appear twice in outline/search/show. Tree-sitter&#39;s <code>decorated_definition</code> wrapper was causing double emission — inner <code>function_definition</code>/<code>class_definition</code> nodes are now skipped when their parent already emitted them.</li></ul><h2 id="_0-4-0-2026-03-24" tabindex="-1">[0.4.0] - 2026-03-24 <a class="header-anchor" href="#_0-4-0-2026-03-24" aria-label="Permalink to &quot;[0.4.0] - 2026-03-24&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Indexing 2x faster</strong> — separated parse workers (parallel, CPU-bound) from serial writer with batched transactions, eliminating goroutine contention on SQLite&#39;s writer lock. Cold index dropped from 2.4s to 1.05s on cli/cli (729 files).</li><li><strong>Reindex 4x faster</strong> — mtime_ns + file size skip check with pre-loaded map avoids reading files or querying DB per-file. Reindex dropped from 57ms to 14ms on cli/cli.</li><li><strong>Prepared statement reuse</strong> — statements prepared once per batch (5 per batch vs 5 per file), reducing cgo overhead on large repos.</li><li><strong>Read-once parse+hash</strong> — workers read each file once and pass bytes to both parser and hasher, eliminating duplicate I/O.</li><li><strong>Row-based batch flushing</strong> — flush at 100 files OR 50k rows (symbols+imports+refs), preventing pathological batches from symbol-dense repos.</li><li><strong>Robust change detection</strong> — mtime stored as nanosecond integer + file size; skip only when both match exactly. Catches coarse FS timestamps and tools that preserve mtime.</li><li><strong>Walker language filtering</strong> — unsupported languages (.json, .md, .toml) filtered before stat, reducing channel traffic and allocations.</li></ul><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Benchmark suite (<code>bench/</code>) comparing cymbal vs ripgrep vs ctags across Go, Python, and TypeScript repos with reproducible pinned corpus.</li><li>Progress indicator on stderr after 10s for large repos (e.g., kubernetes at 16k files).</li><li><code>ParseBytes</code> function for parsing from pre-read byte slices.</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Stale file pruning</strong> — deleted/renamed files are removed from the index on reindex by diffing walker paths against stored paths.</li><li><strong>Savepoint-per-file in batch writer</strong> — a single file write failure no longer corrupts the entire batch; partial data is rolled back cleanly.</li><li><strong>Accurate stats after commit</strong> — indexed/found counts published only after successful tx.Commit(), preventing inflation on commit failure.</li><li><strong>Split error types</strong> — skip reasons separated into unchanged, unsupported, parse_error, write_error; CLI shows non-zero counts conditionally.</li></ul><h2 id="_0-3-0-2026-03-24" tabindex="-1">[0.3.0] - 2026-03-24 <a class="header-anchor" href="#_0-3-0-2026-03-24" aria-label="Permalink to &quot;[0.3.0] - 2026-03-24&quot;">​</a></h2><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Per-repo databases</strong> — each repo gets its own SQLite DB at <code>~/.cymbal/repos/&lt;hash&gt;/index.db</code>, eliminating cross-repo symbol bleed. Searching in repo A no longer returns results from repo B.</li><li>Removed <code>repos</code> table and <code>repo_id</code> column — no longer needed since each DB is one repo</li><li>Added <code>meta</code> table storing <code>repo_root</code> path per database</li><li><code>cymbal ls --repos</code> lists all indexed repos with file/symbol counts</li><li><code>--repo</code> flag removed (repo identity comes from DB path now)</li><li><code>--db</code> flag still works as override for all commands</li></ul><h3 id="added-6" tabindex="-1">Added <a class="header-anchor" href="#added-6" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>refs</code> and <code>impact</code> now show surrounding call-site context (1 line above/below by default, adjustable with <code>-C</code>)</li><li>VitePress docs site at chain.sh/cymbal with chain.sh design language</li></ul><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Stale symbol entries from moved/deleted repos no longer pollute search results</li></ul><h2 id="_0-2-0-2026-03-23" tabindex="-1">[0.2.0] - 2026-03-23 <a class="header-anchor" href="#_0-2-0-2026-03-23" aria-label="Permalink to &quot;[0.2.0] - 2026-03-23&quot;">​</a></h2><h3 id="changed-5" tabindex="-1">Changed <a class="header-anchor" href="#changed-5" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>All commands now output agent-native frontmatter+content format by default (YAML metadata + content body, optimized for LLM token efficiency)</li><li><code>refs</code> and <code>impact</code> deduplicate identical call sites — grouped by file with site count</li><li><code>context</code> callers section uses the same dedup</li><li><code>search</code> results ranked by relevance: exact name match first, then prefix, then contains</li><li>Default limits lowered: refs 50→20, impact 100→50, search 50→20</li><li><code>refs</code>, <code>impact</code>, and <code>context</code> now show actual source lines at call sites, not just line numbers</li></ul><h2 id="_0-1-0-2026-03-23" tabindex="-1">[0.1.0] - 2026-03-23 <a class="header-anchor" href="#_0-1-0-2026-03-23" aria-label="Permalink to &quot;[0.1.0] - 2026-03-23&quot;">​</a></h2><h3 id="added-7" tabindex="-1">Added <a class="header-anchor" href="#added-7" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Core indexing engine with tree-sitter parsing, SQLite FTS5 storage, and AI summaries via oneagent</li><li>Batched summarization with diff tracking and model selection</li><li><code>cymbal index</code> — index a codebase</li><li><code>cymbal ls</code> — list files and repo stats</li><li><code>cymbal outline</code> — show file structure</li><li><code>cymbal search</code> — symbol and text search</li><li><code>cymbal show</code> — display symbol source</li><li><code>cymbal refs</code> — find references to a symbol</li><li><code>cymbal importers</code> — reverse import lookup</li><li><code>cymbal impact</code> — transitive caller analysis</li><li><code>cymbal diff</code> — git diff scoped to a symbol</li><li><code>cymbal context</code> — bundled source, callers, and imports in one call</li></ul><h3 id="fixed-5" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-5" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Overlapping sub-repo detection prevents duplicate symbol indexing</li></ul>',52)])])}const g=a(d,[["render",l]]);export{m as __pageData,g as default};
